def divide(a, b):
    try:
        result = a / b
    except ZeroDivisionError:
        return "Cannot divide by zero"
    except TypeError:
        return "Both arguments must be numbers"
    else:
        return f"Result: {result}"
    finally:
        print("Division attempted")

print(divide(10, 2))
print(divide(10, 0))
print(divide(10, "a"))
